<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      blockStreaming</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// enable block streaming (off by default)</span></span>
